def generate_cache_key(prefix, data):
    """Generate a secure cache key from prefix and data"""
    if isinstance(data, dict):
        data = json.dumps(data, sort_keys=True)
    elif isinstance(data, list):
        data = json.dumps(data, sort_keys=True)
    
    key_string = f"{prefix}:{data}"
    return hashlib.sha256(key_string.encode('utf-8')).hexdigest()

def cache_get(key):
    """Get value from cache with error handling"""
    if not memcached_client:
        return None
    
    try:
        value = memcached_client.get(key)
        return value
    except (MemcacheClientError, MemcacheUnknownCommandError) as e:
        logger.error(f"Memcached get error for key {key}: {e}")
        return None
    except Exception as e:
        logger.error(f"Unexpected error getting from cache: {e}")
        return None

def cache_set(key, value, ttl=300):
    """Set value in cache with error handling"""
    if not memcached_client:
        return False
    
    try:
        memcached_client.set(key, value, expire=ttl)
        return True
    except (MemcacheClientError, MemcacheUnknownCommandError) as e:
        logger.error(f"Memcached set error for key {key}: {e}")
        return False
    except Exception as e:
        logger.error(f"Unexpected error setting cache: {e}")
        return False

def cache_delete(key):
    """Delete value from cache with error handling"""
    if not memcached_client:
        return False
    
    try:
        memcached_client.delete(key)
        return True
    except (MemcacheClientError, MemcacheUnknownCommandError) as e:
        logger.error(f"Memcached delete error for key {key}: {e}")
